// === BBOX UNIÓN + ARRAY DE POLÍGONOS ===
const items = $input.all();

if (items.length === 0) {
  throw new Error('No hay polígonos activos. Verificar zonas_geograficas o array de zonas en query SQL.');
}

let minLat = Infinity, maxLat = -Infinity;
let minLon = Infinity, maxLon = -Infinity;
const polygons = [];

for (const item of items) {
  const data = item.json;
  minLat = Math.min(minLat, parseFloat(data.lat_sur));
  maxLat = Math.max(maxLat, parseFloat(data.lat_norte));
  minLon = Math.min(minLon, parseFloat(data.lon_oeste));
  maxLon = Math.max(maxLon, parseFloat(data.lon_este));

  const geo = JSON.parse(data.geom_geojson);
  polygons.push({
    nombre: data.nombre,
    coordinates: geo.coordinates[0]
  });
}

console.log(`BBox: lat ${minLat} → ${maxLat}, lon ${minLon} → ${maxLon}`);
console.log(`Polígonos: ${polygons.map(p => p.nombre).join(', ')}`);

return [{
  json: {
    bbox: { lat_sur: minLat, lat_norte: maxLat, lon_oeste: minLon, lon_este: maxLon },
    polygons,
    zonas_incluidas: items.map(i => i.json.nombre)
  }
}];

// === GENERADOR DE CUADRANTES C21 ZONA-AGNÓSTICO ===
const config = $input.first().json;
const { lat_sur, lat_norte, lon_oeste, lon_este } = config.bbox;
const STEP = 0.010;

const cookieId = 'sici_' + Math.random().toString(36).substring(2, 15);
const cookie = `PHPSESSID=${cookieId}`;

const cuadrantes = [];
let gridId = 1;

for (let lat = lat_sur; lat < lat_norte; lat += STEP) {
  for (let lon = lon_oeste; lon < lon_este; lon += STEP) {
    const south = lat;
    const west = lon;
    const north = lat + STEP;
    const east = lon + STEP;
    const coordString = `coordenadas_${north.toFixed(6)},${east.toFixed(6)},${south.toFixed(6)},${west.toFixed(6)}`;

    cuadrantes.push({
      json: {
        grid_id: gridId++,
        path_coordenadas: coordString,
        cookie,
        fuente: 'century21'
      }
    });
  }
}

console.log(`Grid generado: ${cuadrantes.length} cuadrantes sobre [${config.zonas_incluidas.join(', ')}]`);
return cuadrantes;

// === EXTRAER PROPIEDADES C21 ALQUILER ===
  // C21 responde: [{ totalHits, results: [...props], aggregations }]
  const response = $input.first().json;

  let results = [];
  if (Array.isArray(response)) {
    // Response es [{results: [...]}] - tomar results del primer elemento
    results = response[0]?.results || [];
  } else if (response?.results) {
    results = Array.isArray(response.results) ? response.results : [];
  } else if (response?.datas?.results) {
    results = Array.isArray(response.datas.results) ? response.datas.results : [];
  }

  if (results.length === 0) {
    return []; // Cuadrante vacío
  }

  return results.map(prop => {
    // Precio: C21 da precio string en BOB + precios.vista en USD
    let precioBob = null;
    let precioUsd = null;
    let moneda = prop.moneda || 'BOB';

    const precioNum = parseFloat(String(prop.precio || '0').replace(/[^0-9.]/g, ''));
    if (precioNum > 0) {
      if (moneda === 'USD') {
        precioUsd = precioNum;
        precioBob = Math.round(precioNum * 6.96 * 100) / 100;
      } else {
        precioBob = precioNum;
        // Usar precio USD de C21 si disponible, sino calcular
        precioUsd = prop.precios?.vista?.precio
          ? Math.round(prop.precios.vista.precio * 100) / 100
          : Math.round(precioNum / 6.96 * 100) / 100;
      }
    }

    // URL: C21 usa urlCorrectaPropiedad (path relativo)
    const rawUrl = prop.urlCorrectaPropiedad || prop.url || null;
    const url = rawUrl
      ? (rawUrl.startsWith('http') ? rawUrl : `https://c21.com.bo${rawUrl}`)
      : null;

    return {
      json: {
        url: url,
        fuente: 'century21',
        codigo_propiedad: prop.id?.toString() || prop.folio || null,
        tipo_operacion: 'alquiler',
        tipo_propiedad_original: prop.tipoPropiedad || 'departamento',
        precio_bob: precioBob,
        precio_usd: precioUsd,
        moneda_original: moneda,
        area_total_m2: prop.m2C || null,
        dormitorios: prop.recamaras != null ? parseInt(prop.recamaras) : null,
        banos: prop.banos != null ? parseFloat(prop.banos) : null,
        estacionamientos: prop.estacionamientos != null ? parseInt(prop.estacionamientos) : null,
        latitud: prop.lat ? parseFloat(prop.lat) : null,
        longitud: prop.lon ? parseFloat(prop.lon) : null,
        fecha_publicacion: prop.fechaAlta || null,
        datos_json_discovery: prop,
        metodo_discovery: 'zonanorte_c21_alquiler'
      }
    };
  }).filter(p => p.json.url !== null);

// === FILTRO POINT-IN-POLYGON (FUERA DEL LOOP) ===
// Filtra el array completo de propiedades del Aggregate.
function pointInPolygon(lon, lat, ring) {
  let inside = false;
  for (let i = 0, j = ring.length - 1; i < ring.length; j = i++) {
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    const intersect = ((yi > lat) !== (yj > lat)) &&
      (lon < (xj - xi) * (lat - yi) / (yj - yi) + xi);
    if (intersect) inside = !inside;
  }
  return inside;
}

const polygons = $('Calcular BBox + Polígonos').first().json.polygons || [];
if (polygons.length === 0) {
  console.warn('Sin polígonos activos — devuelvo vacío (FAIL CLOSED)');
  return [{ json: { propiedades: [], stats: { total: 0, dentro: 0, fuera: 0 } } }];
}

const input = $input.first().json;
const propiedades = input.propiedades || [];

const dentro = propiedades.filter(p => {
  const lat = parseFloat(p.latitud);
  const lon = parseFloat(p.longitud);
  if (!Number.isFinite(lat) || !Number.isFinite(lon)) return false;
  return polygons.some(poly => pointInPolygon(lon, lat, poly.coordinates));
});

console.log(`Filtro polígono: ${dentro.length}/${propiedades.length} dentro de [${polygons.map(p => p.nombre).join(', ')}]`);

return [{
  json: {
    propiedades: dentro,
    stats: {
      total: propiedades.length,
      dentro: dentro.length,
      fuera: propiedades.length - dentro.length
    }
  }
}];

// === PREPARAR COMPARACIÓN ===
// Lee las propiedades del nodo Filtrar (ya filtradas por polígono) y compara con BD.
const snapshot = $('Filtrar por Polígonos').first().json.propiedades || [];
const propiedadesBD = $('Obtener URLs Activas BD').all().map(item => item.json);

const snapshotDedup = new Map();
for (const prop of snapshot) {
  snapshotDedup.set(prop.url, prop);
}

const urlsSnapshot = new Set(snapshotDedup.keys());
const urlsBD = new Map(propiedadesBD.map(p => [p.url, { id: p.id, status: p.status }]));

const nuevas = [];
const existentes = [];
const ausentes = [];

for (const [url, prop] of snapshotDedup) {
  if (!urlsBD.has(url)) {
    nuevas.push(prop);
  } else {
    existentes.push({
      ...prop,
      _id_bd: urlsBD.get(url).id,
      _status_bd: urlsBD.get(url).status
    });
  }
}

for (const [url, info] of urlsBD) {
  if (!urlsSnapshot.has(url)) {
    if (!['inactivo_pending', 'inactivo_confirmed'].includes(info.status)) {
      ausentes.push({
        id: info.id,
        url: url,
        status_actual: info.status
      });
    }
  }
}

return [{
  json: {
    nuevas,
    existentes,
    ausentes,
    stats: {
      total_snapshot: snapshotDedup.size,
      total_bd: urlsBD.size,
      nuevas: nuevas.length,
      existentes: existentes.length,
      ausentes: ausentes.length
    }
  }
}];

// === LOG STATS ===
const stats = $input.first().json.stats;

console.log(`
=== DISCOVERY C21 ALQUILER ZONA NORTE ===
Snapshot (deduplicado): ${stats.total_snapshot}
BD activas (zonas activas): ${stats.total_bd}
---
Nuevas: ${stats.nuevas}
Existentes: ${stats.existentes}
Ausentes: ${stats.ausentes}
=========================================
`);

return $input.all();

// === PREPARAR PARA registrar_discovery_alquiler() ===
const data = $input.first().json;
const nuevas = data.nuevas || [];
const existentes = data.existentes || [];
const todas = [...nuevas, ...existentes];

if (todas.length === 0) {
  return [{ json: { skip: true, message: 'No hay alquileres C21 Zona Norte para procesar' } }];
}

return todas.map(prop => ({
  json: {
    p_url: prop.url,
    p_fuente: prop.fuente,
    p_codigo_propiedad: prop.codigo_propiedad,
    p_precio_mensual_bob: prop.precio_bob,
    p_precio_mensual_usd: prop.precio_usd,
    p_moneda_original: prop.moneda_original || 'BOB',
    p_area_total_m2: prop.area_total_m2,
    p_dormitorios: prop.dormitorios,
    p_banos: prop.banos,
    p_estacionamientos: prop.estacionamientos,
    p_tipo_propiedad_original: prop.tipo_propiedad_original,
    p_latitud: prop.latitud,
    p_longitud: prop.longitud,
    p_fecha_publicacion: prop.fecha_publicacion,
    p_metodo_discovery: prop.metodo_discovery,
    p_zona: null,
    p_datos_json_discovery: JSON.stringify(prop.datos_json_discovery)
  }
}));

// === PROCESAR AUSENTES ===
const ausentes = $input.first().json.ausentes;

if (ausentes.length === 0) {
  return [{ json: { skip: true, message: 'No hay propiedades ausentes' } }];
}

return ausentes.map(prop => ({
  json: {
    id: prop.id,
    url: prop.url,
    status_actual: prop.status_actual
  }
}));

// === RESUMEN FINAL ===
const stats = $('Log Stats').first().json.stats;
const zonas = $('Calcular BBox + Polígonos').first().json.zonas_incluidas;

const resumen = {
  timestamp: new Date().toISOString(),
  fuente: 'century21',
  workflow: 'Discovery C21 Alquiler Zona Norte',
  version: '1.0.0',
  zonas_activas: zonas,
  resultados: {
    snapshot_total: stats.total_snapshot,
    bd_activas: stats.total_bd,
    nuevas_insertadas: stats.nuevas,
    existentes_actualizadas: stats.existentes,
    ausentes_marcadas: stats.ausentes
  },
  status: 'completado'
};

console.log('=== DISCOVERY C21 ALQUILER ZONA NORTE COMPLETADO ===');
console.log(JSON.stringify(resumen, null, 2));

return [{ json: resumen }];
